import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: Submit Survey */
  onSubmit?: (answers: {
    name: string;
    email: string;
    satisfactionRating: string;
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

const defaultProps: Props = {
  featureOptions: ['Performance', 'UI Improvements', 'Integrations', 'Reporting'],
  satisfactionLabels: ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit: async () => undefined,
};

export default function GeneratedComponent(props: Props) {
  const merged = { ...defaultProps, ...props };
  const totalSteps = 5;
  const [currentStep, setCurrentStep] = useState(1);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touchedName, setTouchedName] = useState(false);
  const [touchedEmail, setTouchedEmail] = useState(false);
  const [touchedSatisfaction, setTouchedSatisfaction] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touchedName && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touchedEmail && !email.trim()
      ? 'Email is required.'
      : touchedEmail && !emailValid
      ? 'Please enter a valid email address.'
      : '';
  const satisfactionError = touchedSatisfaction && !satisfactionRating ? 'Please select a satisfaction rating.' : '';

  const stepValid =
    (currentStep === 1 && name.trim() && email.trim() && emailValid) ||
    (currentStep === 2 && !!satisfactionRating) ||
    (currentStep === 3 && true) ||
    (currentStep === 4 && comments.length <= 500) ||
    currentStep === 5;

  const handleNext = () => {
    if (currentStep === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
    }
    if (currentStep === 2) setTouchedSatisfaction(true);
    if (!stepValid) return;
    setCurrentStep((s) => Math.min(totalSteps, s + 1));
  };

  const handleBack = () => setCurrentStep((s) => Math.max(1, s - 1));

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) => (checked ? [...prev, feature] : prev.filter((f) => f !== feature)));
  };

  const handleSubmit = async () => {
    setFeedback(null);
    setIsSubmitting(true);
    try {
      await merged.onSubmit?.({
        name: name.trim(),
        email: email.trim(),
        satisfactionRating,
        featureInterests,
        comments,
      });
      setFeedback({ type: 'success', message: 'Survey submitted successfully.' });
    } catch (e) {
      setFeedback({ type: 'error', message: 'Failed to submit survey. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        maxWidth: '720px',
        margin: '0 auto',
      }}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of {totalSteps}
          </Text>
          <Progress value={currentStep} max={totalSteps} size="md" variant="default" />
        </Stack>

        {currentStep === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Contact Information
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              placeholder="Enter your full name"
              error={nameError}
              onBlur={() => setTouchedName(true)}
              aria-label="Name"
            />
            <Input
              label="Email"
              value={email}
              onChange={setEmail}
              required
              type="email"
              placeholder="Enter your email"
              error={emailError}
              onBlur={() => setTouchedEmail(true)}
              aria-label="Email"
            />
          </Stack>
        )}

        {currentStep === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you? (1–5)"
              value={satisfactionRating}
              onChange={setSatisfactionRating}
              error={satisfactionError}
              options={merged.satisfactionLabels.map((label, idx) => ({
                value: String(idx + 1),
                label: `${idx + 1} - ${label}`,
              }))}
            />
          </Stack>
        )}

        {currentStep === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all that apply
            </Text>
            <Stack gap={8}>
              {merged.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={featureInterests.includes(feature)}
                  onChange={(checked) => toggleFeature(feature, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {currentStep === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              placeholder="Share anything else you'd like us to know..."
              helperText="Maximum 500 characters."
              aria-label="Comments"
            />
          </Stack>
        )}

        {currentStep === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Review Your Answers
            </Text>
            <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={4} />
            <Stack gap={8}>
              <Text variant="label">Name</Text>
              <Text>{name || '—'}</Text>

              <Text variant="label">Email</Text>
              <Text>{email || '—'}</Text>

              <Text variant="label">Satisfaction</Text>
              <Text>
                {satisfactionRating
                  ? `${satisfactionRating} - ${merged.satisfactionLabels[Number(satisfactionRating) - 1] ?? ''}`
                  : '—'}
              </Text>

              <Text variant="label">Feature Interests</Text>
              <Text>{featureInterests.length ? featureInterests.join(', ') : 'None selected'}</Text>

              <Text variant="label">Comments</Text>
              <Text>{comments || 'No comments'}</Text>
            </Stack>
          </Stack>
        )}

        {feedback && (
          <Alert variant={feedback.type === 'success' ? 'success' : 'error'} title={feedback.type === 'success' ? 'Success' : 'Error'}>
            {feedback.message}
          </Alert>
        )}

        <Stack direction="horizontal" justify="between" gap={12}>
          <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1 || isSubmitting}>
            Back
          </Button>

          {currentStep < totalSteps ? (
            <Button variant="primary" onClick={handleNext} disabled={!stepValid || isSubmitting}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting}>
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
  lanthanide: 'var(--ggui-color-neutral-500, #6b7280)',
  actinide: 'var(--ggui-color-neutral-700, #374151)',
  unknown: 'var(--ggui-color-outline, #d4d4d8)',
};

export default function GeneratedComponent(props: Props) {
  const {
    elements = [],
  } = props;

  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(undefined);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const selectedElement = useMemo(
    () => elements.find((el) => el.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
    const all = elements
      .map((e) => (e.category ?? 'unknown').trim().toLowerCase())
      .filter(Boolean);
    return Array.from(new Set(all));
  }, [elements]);

  return (
    <Card
      padding={16}
      radius="lg"
      shadow="sm"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack gap={16}>
        <Text variant="label" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          placeholder="Filter by name or symbol"
          value={query}
          onChange={setQuery}
          aria-label="Search elements by name or symbol"
          helperText={`Showing ${filteredElements.length} of ${elements.length} elements`}
        />

        <Card
          padding={12}
          radius="md"
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            {filteredElements.map((element) => {
              const categoryKey = (element.category ?? 'unknown').trim().toLowerCase();
              const cellColor =
                categoryColorMap[categoryKey] ?? 'var(--ggui-color-outline, #d4d4d8)';
              const isSelected = selectedAtomicNumber === element.atomicNumber;
              const label = `${element.name ?? 'Unknown'} (${element.symbol ?? '?'})`;

              return (
                <Button
                  key={`${element.atomicNumber ?? 'na'}-${element.symbol ?? 'x'}-${element.row ?? 0}-${element.col ?? 0}`}
                  variant={isSelected ? 'primary' : 'ghost'}
                  size="sm"
                  aria-label={`Select ${label}`}
                  onClick={() => setSelectedAtomicNumber(element.atomicNumber)}
                  style={{
                    gridColumn: `${element.col ?? 1}`,
                    gridRow: `${element.row ?? 1}`,
                    minHeight: '64px',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    background: isSelected
                      ? 'var(--ggui-color-primary-100, #e0f2fe)'
                      : 'var(--ggui-color-surface, #fafafa)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' : 'none',
                    position: 'relative',
                    transition: 'background-color 200ms ease, border-color 200ms ease, transform 100ms ease',
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: '4px',
                      left: '6px',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      lineHeight: 1,
                    }}
                  >
                    {element.atomicNumber ?? ''}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-xl, 20px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      lineHeight: 1,
                      display: 'inline-flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      width: '100%',
                      height: '100%',
                      textAlign: 'center',
                      color: cellColor,
                    }}
                  >
                    {element.symbol ?? '?'}
                  </span>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={12}
          radius="md"
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surface, #fafafa)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={6}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <>
                <Text variant="body"><strong>Name:</strong> {selectedElement.name ?? '—'}</Text>
                <Text variant="body"><strong>Symbol:</strong> {selectedElement.symbol ?? '—'}</Text>
                <Text variant="body"><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}</Text>
                <Text variant="body"><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}</Text>
                <Text variant="body"><strong>Category:</strong> {selectedElement.category ?? 'unknown'}</Text>
              </>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element in the table to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={12}
          radius="md"
          border
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" gap={8} wrap>
              {categories.map((category) => {
                const swatchColor = categoryColorMap[category] ?? 'var(--ggui-color-outline, #d4d4d8)';
                return (
                  <Card
                    key={category}
                    padding="6px 10px"
                    radius="sm"
                    border
                    shadow="none"
                    style={{
                      borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      background: 'var(--ggui-color-surface, #fafafa)',
                    }}
                  >
                    <Stack direction="horizontal" gap={6} align="center">
                      <span
                        aria-hidden="true"
                        style={{
                          width: '10px',
                          height: '10px',
                          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                          background: swatchColor,
                          border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                          flexShrink: 0,
                        }}
                      />
                      <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                        {category}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: send callback */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount = 0,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const listRef = useRef<HTMLDivElement>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, [allMessages.length]);

  useEffect(() => {
    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      if (customEvent?.detail && (customEvent.detail.text || customEvent.detail.sender)) {
        setStreamMessages((prev) => [...prev, customEvent.detail]);
      }
    };

    window.addEventListener('ggui:agent-data', onAgentData);
    return () => window.removeEventListener('ggui:agent-data', onAgentData);
  }, []);

  const handleSend = () => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    sendMessage(payload);
    setDraft('');
  };

  const onKeyDown: React.KeyboardEventHandler<HTMLInputElement> = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card
      padding={0}
      shadow="sm"
      border
      radius="lg"
    >
      <Stack gap={0}>
        <Stack
          direction="horizontal"
          align="center"
          justify="between"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
          >
            {title}
          </Text>
          <Badge variant="primary" size="sm" aria-label="Participant count">
            {participantCount}
          </Badge>
        </Stack>

        <Stack
          gap={0}
          style={{
            height: 'var(--ggui-chat-height, 420px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack
            gap={0}
            style={{
              flex: 1,
              overflowY: 'auto',
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
            ref={listRef}
            aria-label="Message list"
            role="log"
            aria-live="polite"
          >
            {allMessages.map((message, index) => {
              const sender = message.sender || '';
              const text = message.text || '';
              const timestamp = message.timestamp || '';
              const isOwn = sender === currentUser;
              const previousSender = index > 0 ? allMessages[index - 1]?.sender || '' : '';
              const startsGroup = index === 0 || previousSender !== sender;

              const timeLabel = timestamp
                ? new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
                : '';

              return (
                <Stack
                  key={`${sender}-${timestamp}-${index}`}
                  align={isOwn ? 'end' : 'start'}
                  gap={4}
                  style={{
                    marginTop: startsGroup ? 'var(--ggui-spacing-4, 16px)' : 'var(--ggui-spacing-1, 4px)',
                  }}
                >
                  {startsGroup ? (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {sender || 'Unknown'}
                    </Text>
                  ) : null}

                  <Stack
                    gap={4}
                    style={{
                      maxWidth: '80%',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                      background: isOwn
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                    }}
                  >
                    <Text
                      variant="body"
                      color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                    >
                      {text}
                    </Text>
                    <Text
                      variant="caption"
                      color={
                        isOwn
                          ? 'var(--ggui-color-primary-100, #e0f2fe)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                      align="right"
                    >
                      {timeLabel}
                    </Text>
                  </Stack>
                </Stack>
              );
            })}
          </Stack>

          <Stack
            direction="horizontal"
            gap="var(--ggui-spacing-2, 8px)"
            align="end"
            style={{
              borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            <div style={{ flex: 1 }}>
              <Input
                label="Type a message"
                placeholder="Write a message..."
                value={draft}
                onChange={setDraft}
                onKeyDown={onKeyDown}
                aria-label="Message input"
              />
            </div>
            <Button
              variant="primary"
              size="md"
              onClick={handleSend}
              disabled={!draft.trim()}
              aria-label="Send message"
            >
              Send
            </Button>
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ['😀', '🧑‍💻', '🎨', '🚀'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  complete,
}: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState<number>(1);

  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile.avatar ?? avatarOptions[0] ?? '');
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({
    name: false,
    email: false,
  });

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailValid
      ? 'Please enter a valid email address.'
      : '';

  const step1Valid = !!name.trim() && !!email.trim() && emailValid && !!avatar;
  const step2Valid = !!role;

  const canNext = currentStep === 1 ? step1Valid : currentStep === 2 ? step2Valid : true;
  const progressValue = (currentStep / 3) * 100;

  const animatedStyle = motionEnabled
    ? {
        animation: 'ggui-slideInUp 200ms ease-out',
      }
    : undefined;

  const handleNext = () => {
    if (currentStep === 1) {
      setTouched({ name: true, email: true });
      if (!step1Valid) return;
    }
    if (currentStep === 2 && !step2Valid) return;
    setCurrentStep((s) => Math.min(3, s + 1));
  };

  const handleBack = () => setCurrentStep((s) => Math.max(1, s - 1));

  const handleComplete = () => {
    if (!step1Valid || !step2Valid) return;
    complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        border
        radius="lg"
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-live="polite"
            >
              Step {currentStep} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          <Card
            padding={16}
            border
            shadow="none"
            radius="md"
          >
            <Stack gap={16}>
              {currentStep === 1 && (
                <Stack gap={16} style={animatedStyle}>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    Profile Setup
                  </Text>

                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    required
                    placeholder="Enter your name"
                    error={nameError || undefined}
                    onBlur={() => setTouched((t) => ({ ...t, name: true }))}
                    aria-label="Name"
                  />

                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    required
                    placeholder="Enter your email"
                    error={emailError || undefined}
                    onBlur={() => setTouched((t) => ({ ...t, email: true }))}
                    aria-label="Email"
                  />

                  <Stack gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      Avatar
                    </Text>
                    <Stack direction="horizontal" gap={8} wrap>
                      {avatarOptions.map((option) => {
                        const selected = avatar === option;
                        return (
                          <Button
                            key={option}
                            variant={selected ? 'primary' : 'outline'}
                            size="md"
                            onPress={() => setAvatar(option)}
                            aria-label={`Select avatar ${option}`}
                          >
                            {option}
                          </Button>
                        );
                      })}
                    </Stack>
                  </Stack>
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack gap={16} style={animatedStyle}>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    Preferences
                  </Text>

                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    placeholder="Select your role"
                    options={roleOptions.map((r) => ({ value: r, label: r }))}
                    required
                    error={!role ? 'Role is required before continuing.' : undefined}
                    aria-label="Role"
                  />

                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />

                  <Toggle
                    label={`Theme preference (${theme})`}
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  />
                </Stack>
              )}

              {currentStep === 3 && (
                <Stack gap={12} style={animatedStyle}>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    Review & Confirm
                  </Text>

                  <Card padding={12} shadow="none" border radius="md">
                    <Stack gap={8}>
                      <Text variant="body"><strong>Name:</strong> {name || '—'}</Text>
                      <Text variant="body"><strong>Email:</strong> {email || '—'}</Text>
                      <Text variant="body"><strong>Avatar:</strong> {avatar || '—'}</Text>
                      <Text variant="body"><strong>Role:</strong> {role || '—'}</Text>
                      <Text variant="body">
                        <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                      </Text>
                      <Text variant="body"><strong>Theme:</strong> {theme}</Text>
                    </Stack>
                  </Card>
                </Stack>
              )}
            </Stack>
          </Card>

          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              onPress={handleBack}
              disabled={currentStep === 1}
              aria-label="Go back"
            >
              Back
            </Button>

            {currentStep < 3 ? (
              <Button
                variant="primary"
                onPress={handleNext}
                disabled={!canNext}
                aria-label="Next step"
              >
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="outline" onPress={handleBack} aria-label="Edit previous step">
                  Go Back
                </Button>
                <Button
                  variant="primary"
                  onPress={handleComplete}
                  disabled={!step1Valid || !step2Valid}
                  aria-label="Complete setup"
                >
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
      {`__GGUI_META__{"category":"Forms","description":"A 3-step onboarding wizard with validation, progress indicator, editable defaults, review step, and completion callback wiring."}`}
    </>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit callback from Action Contract */
  onSubmit?: (payload: {
    name: string;
    email: string;
    satisfaction: {
      rating: number;
      label: string;
    };
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

const defaultFeatureOptions = [
  'Performance improvements',
  'Collaboration tools',
  'AI assistance',
  'Mobile support',
];

const defaultSatisfactionLabels = [
  'Very Unsatisfied',
  'Unsatisfied',
  'Neutral',
  'Satisfied',
  'Very Satisfied',
];

export default function GeneratedComponent({
  featureOptions = defaultFeatureOptions,
  satisfactionLabels = defaultSatisfactionLabels,
  onSubmit,
}: Props) {
  const totalSteps = 5;
  const [step, setStep] = useState(1);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState({
    name: false,
    email: false,
    satisfaction: false,
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitState, setSubmitState] = useState<'idle' | 'success' | 'error'>('idle');
  const [submitMessage, setSubmitMessage] = useState('');

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailRegex.test(email)
      ? 'Please enter a valid email address.'
      : '';
  const satisfactionError = touched.satisfaction && !satisfaction ? 'Please select a rating.' : '';

  const satisfactionOptions = useMemo(
    () =>
      satisfactionLabels.map((label, idx) => ({
        value: String(idx + 1),
        label,
      })),
    [satisfactionLabels]
  );

  const canNextFromStep = (currentStep: number) => {
    if (currentStep === 1) return !!name.trim() && emailRegex.test(email);
    if (currentStep === 2) return !!satisfaction;
    if (currentStep === 3) return true;
    if (currentStep === 4) return comments.length <= 500;
    return true;
  };

  const onToggleFeature = (option: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, option] : prev.filter((item) => item !== option)
    );
  };

  const handleNext = () => {
    if (step === 1) setTouched((p) => ({ ...p, name: true, email: true }));
    if (step === 2) setTouched((p) => ({ ...p, satisfaction: true }));

    if (!canNextFromStep(step)) return;
    setStep((s) => Math.min(totalSteps, s + 1));
  };

  const handleBack = () => {
    setStep((s) => Math.max(1, s - 1));
  };

  const handleSubmit = async () => {
    if (!onSubmit) return;
    setIsSubmitting(true);
    setSubmitState('idle');
    setSubmitMessage('');

    try {
      await onSubmit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: {
          rating: Number(satisfaction),
          label: satisfactionLabels[Number(satisfaction) - 1] || '',
        },
        featureInterests,
        comments: comments.trim(),
      });
      setSubmitState('success');
      setSubmitMessage('Survey submitted successfully.');
    } catch (error) {
      setSubmitState('error');
      setSubmitMessage('Failed to submit survey. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      aria-label="Multi-step survey form"
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={step} max={totalSteps} size="md" />
        </Stack>

        {submitState !== 'idle' && (
          <Alert variant={submitState === 'success' ? 'success' : 'error'} title={submitState === 'success' ? 'Success' : 'Error'}>
            {submitMessage}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Contact Information
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              error={nameError}
              placeholder="Enter your name"
              aria-label="Name"
              onBlur={() => setTouched((p) => ({ ...p, name: true }))}
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError}
              placeholder="Enter your email"
              aria-label="Email"
              onBlur={() => setTouched((p) => ({ ...p, email: true }))}
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you?"
              value={satisfaction}
              onChange={setSatisfaction}
              options={satisfactionOptions}
              error={satisfactionError}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all that apply.
            </Text>
            <Stack gap={8}>
              {featureOptions.map((option) => (
                <Checkbox
                  key={option}
                  label={option}
                  checked={featureInterests.includes(option)}
                  onChange={(checked) => onToggleFeature(option, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={(value) => setComments(value.slice(0, 500))}
              rows={6}
              maxLength={500}
              showCount
              helperText="Share any additional thoughts"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Review Your Answers
            </Text>
            <Card
              padding={16}
              shadow="none"
              border
              radius="md"
            >
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {name || '-'}</Text>
                <Text variant="body"><strong>Email:</strong> {email || '-'}</Text>
                <Text variant="body">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfaction ? `${satisfaction} - ${satisfactionLabels[Number(satisfaction) - 1] || ''}` : '-'}
                </Text>
                <Text variant="body">
                  <strong>Feature Interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : '-'}
                </Text>
                <Text variant="body"><strong>Comments:</strong> {comments || '-'}</Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={8}>
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1 || isSubmitting}
            aria-label="Go to previous step"
          >
            Back
          </Button>

          {step < totalSteps ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canNextFromStep(step) && step !== 1 && step !== 2 ? false : !canNextFromStep(step)}
              aria-label="Go to next step"
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              loading={isSubmitting}
              disabled={isSubmitting}
              aria-label="Submit survey"
            >
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(undefined);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(
    () =>
      elements.filter((el) => {
        if (!normalizedQuery) return true;
        const name = (el.name ?? '').toLowerCase();
        const symbol = (el.symbol ?? '').toLowerCase();
        return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
      }),
    [elements, normalizedQuery]
  );

  const selectedElement = useMemo(
    () =>
      elements.find((el) => el.atomicNumber === selectedAtomicNumber) ??
      filteredElements[0] ??
      null,
    [elements, filteredElements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [elements]);

  const categoryColor = (category?: string) => {
    const key = (category ?? '').toLowerCase();
    const map: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
      'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
      'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
      metalloid: 'var(--ggui-color-success-500, #22c55e)',
      nonmetal: 'var(--ggui-color-success-600, #16a34a)',
      halogen: 'var(--ggui-color-warning-600, #d97706)',
      'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
      lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
      actinide: 'var(--ggui-color-error-600, #dc2626)',
      unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
    };
    return map[key] ?? 'var(--ggui-color-neutral-400, #9ca3af)';
  };

  return (
    <Stack gap={16}>
      <Text
        variant="bodyLarge"
        weight="semibold"
        color="var(--ggui-color-onSurface, #18181b)"
      >
        Periodic Table of Elements
      </Text>

      <Input
        label="Search elements"
        type="search"
        placeholder="Search by name or symbol..."
        value={query}
        onChange={setQuery}
        aria-label="Search elements by name or symbol"
      />

      <Card
        padding={12}
        border
        radius="lg"
        shadow="sm"
      >
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          role="grid"
          aria-label="Periodic table grid"
        >
          {filteredElements.map((el) => {
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            return (
              <button
                key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'unknown'}`}
                type="button"
                onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                style={{
                  gridColumn: el.col ?? 'auto',
                  gridRow: el.row ?? 'auto',
                  minHeight: '64px',
                  border: `1px solid ${
                    isSelected
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-outline, #d4d4d8)'
                  }`,
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  color: 'var(--ggui-color-onSurface, #18181b)',
                  cursor: 'pointer',
                  position: 'relative',
                  padding: '6px',
                  transition:
                    'transform 200ms ease, border-color 200ms ease, box-shadow 200ms ease',
                  boxShadow: isSelected
                    ? '0 0 0 2px var(--ggui-color-primary-200, #bae6fd)'
                    : 'none',
                }}
                aria-label={`${el.name ?? 'Unknown'} (${el.symbol ?? ''})`}
              >
                <span
                  style={{
                    position: 'absolute',
                    top: '4px',
                    left: '6px',
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                  }}
                >
                  {el.atomicNumber ?? ''}
                </span>
                <span
                  style={{
                    display: 'block',
                    textAlign: 'center',
                    fontSize: 'var(--ggui-font-size-xl, 20px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    color: categoryColor(el.category),
                    lineHeight: 1.2,
                    marginTop: '10px',
                  }}
                >
                  {el.symbol ?? '?'}
                </span>
              </button>
            );
          })}
        </div>
      </Card>

      <Card padding={16} border radius="lg" shadow="sm">
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Element Details
          </Text>
          {selectedElement ? (
            <Stack gap={4}>
              <Text variant="body"><strong>Name:</strong> {selectedElement.name ?? '—'}</Text>
              <Text variant="body"><strong>Symbol:</strong> {selectedElement.symbol ?? '—'}</Text>
              <Text variant="body"><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}</Text>
              <Text variant="body"><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}</Text>
              <Text variant="body"><strong>Category:</strong> {selectedElement.category ?? '—'}</Text>
            </Stack>
          ) : (
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No element selected.
            </Text>
          )}
        </Stack>
      </Card>

      <Card padding={16} border radius="lg" shadow="sm">
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Legend
          </Text>
          <Stack direction="horizontal" wrap gap={8}>
            {categories.map((category) => (
              <div
                key={category}
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '6px',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  padding: '4px 10px',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                }}
              >
                <span
                  aria-hidden="true"
                  style={{
                    width: '10px',
                    height: '10px',
                    borderRadius: '9999px',
                    background: categoryColor(category),
                    display: 'inline-block',
                  }}
                />
                <Text as="span" variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                  {category}
                </Text>
              </div>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Stack>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Box, Button, Card, Heading, Input, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract callback: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type MessageItem = { sender?: string; text?: string; timestamp?: string };
type MessageGroup = { sender?: string; items: MessageItem[] };

export default function GeneratedComponent({
  title = '',
  currentUser = '',
  participantCount = undefined,
  messages = [],
  sendMessage = undefined,
}: Props) {
  const [draftText, setDraftText] = useState<string>('');
  const messagesViewportRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    const el = messagesViewportRef.current;
    if (!el) return;
    el.scrollTop = el.scrollHeight;
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    const handler = () => {
      // Stream contract listener: parent is expected to update `messages` prop.
      scrollToBottom();
    };
    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const groupedMessages = useMemo<MessageGroup[]>(() => {
    const groups: MessageGroup[] = [];
    messages.forEach((msg) => {
      const prev = groups[groups.length - 1];
      if (!prev || (prev.sender ?? '') !== (msg.sender ?? '')) {
        groups.push({ sender: msg.sender, items: [msg] });
      } else {
        prev.items.push(msg);
      }
    });
    return groups;
  }, [messages]);

  const formatTime = (raw?: string) => {
    if (!raw) return '';
    const d = new Date(raw);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const submitMessage = () => {
    const trimmed = draftText.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    sendMessage?.({ text: trimmed, timestamp });
    setDraftText('');
    requestAnimationFrame(scrollToBottom);
  };

  const isSendDisabled = draftText.trim().length === 0;

  return (
    <Card
      shadow="sm"
      radius="lg"
      border
      padding={0}
      role="region"
      aria-label={`${title} chat`}
    >
      <Stack
        gap={0}
        style={{
          height: '560px',
          background: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <Box
          padding="var(--ggui-spacing-4, 16px)"
          style={{
            borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">
              {title}
            </Heading>
            {typeof participantCount === 'number' ? (
              <Badge variant="primary" size="sm" pill>
                {participantCount}
              </Badge>
            ) : null}
          </Stack>
        </Box>

        <Box
          ref={messagesViewportRef}
          role="log"
          aria-live="polite"
          aria-relevant="additions text"
          padding="var(--ggui-spacing-4, 16px)"
          style={{
            flex: 1,
            overflowY: 'auto',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack gap="var(--ggui-spacing-4, 16px)">
            {groupedMessages.map((group, groupIndex) => {
              const isOwn = (group.sender ?? '') === currentUser;
              return (
                <Stack
                  key={`${groupIndex}-${group.sender ?? 'unknown'}`}
                  align={isOwn ? 'end' : 'start'}
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {group.sender ?? 'Unknown'}
                  </Text>

                  <Stack gap="var(--ggui-spacing-1, 4px)" align={isOwn ? 'end' : 'start'}>
                    {group.items.map((item, itemIndex) => (
                      <Box
                        key={`${groupIndex}-${itemIndex}-${item.timestamp ?? 'na'}`}
                        padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                        style={{
                          maxWidth: '80%',
                          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                          background: isOwn
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        }}
                      >
                        <Stack gap="var(--ggui-spacing-1, 4px)">
                          <Text
                            variant="bodySmall"
                            color={
                              isOwn
                                ? 'var(--ggui-color-surface, #fafafa)'
                                : 'var(--ggui-color-onSurface, #18181b)'
                            }
                          >
                            {item.text ?? ''}
                          </Text>
                          <Text
                            variant="caption"
                            color={
                              isOwn
                                ? 'var(--ggui-color-surface, #fafafa)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                            align={isOwn ? 'right' : 'left'}
                          >
                            {formatTime(item.timestamp)}
                          </Text>
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                </Stack>
              );
            })}
          </Stack>
        </Box>

        <Box
          padding="var(--ggui-spacing-4, 16px)"
          style={{
            borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Stack direction="horizontal" gap={8} align="end">
            <Box style={{ flex: 1 }}>
              <Input
                size="md"
                placeholder="Type a message..."
                aria-label="Message input"
                value={draftText}
                onChange={setDraftText}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    submitMessage();
                  }
                }}
              />
            </Box>
            <Button
              variant="primary"
              size="md"
              aria-label="Send message"
              disabled={isSendDisabled}
              onClick={submitMessage}
            >
              Send
            </Button>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

