import React, { useEffect, useMemo, useState } from 'react';
import { Box, Card, Container, Heading, Spinner, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

type ConnectionState = 'connecting' | 'live' | 'stale';

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = undefined,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [connectionState, setConnectionState] = useState<ConnectionState>('connecting');
  const [isInitialLoading, setIsInitialLoading] = useState<boolean>(true);
  const [lastStreamTick, setLastStreamTick] = useState<number>(Date.now());

  useEffect(() => {
    setLiveStocks(stocks);
    if (stocks.length > 0) {
      setIsInitialLoading(false);
      setConnectionState((prev) => (prev === 'connecting' ? 'live' : prev));
    }
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
    if (lastUpdated) {
      setIsInitialLoading(false);
      setConnectionState((prev) => (prev === 'connecting' ? 'live' : prev));
    }
  }, [lastUpdated]);

  useEffect(() => {
    setConnectionState('connecting');

    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{
        stocks?: Props['stocks'];
        lastUpdated?: string;
      }>;
      const detail = customEvent?.detail;

      if (!detail || typeof detail !== 'object') return;

      let updated = false;

      if (Array.isArray(detail.stocks)) {
        setLiveStocks(detail.stocks);
        updated = true;
      }

      if (typeof detail.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
        updated = true;
      }

      if (updated) {
        setIsInitialLoading(false);
        setConnectionState('live');
        setLastStreamTick(Date.now());
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  useEffect(() => {
    const interval = window.setInterval(() => {
      if (connectionState === 'live' && Date.now() - lastStreamTick > 30000) {
        setConnectionState('stale');
      }
    }, 1000);

    return () => window.clearInterval(interval);
  }, [connectionState, lastStreamTick]);

  const formattedLastUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const parsed = new Date(liveLastUpdated);
    if (Number.isNaN(parsed.getTime())) return liveLastUpdated;
    return parsed.toLocaleString();
  }, [liveLastUpdated]);

  const showLoading = isInitialLoading && liveStocks.length === 0;

  return (
    <Box
      background="var(--ggui-color-surface, #fafafa)"
      padding="var(--ggui-spacing-6, 24px)"
      style={{ minHeight: '100%' }}
    >
      <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            <Stack gap="var(--ggui-spacing-1, 4px)" aria-live="polite">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                {formattedLastUpdated}
              </Text>
            </Stack>
          </Stack>

          {showLoading && (
            <Box
              role="status"
              aria-live="polite"
              padding="var(--ggui-spacing-6, 24px)"
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
                border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              }}
            >
              <Spinner size={20} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Connecting to live market feed…
              </Text>
            </Box>
          )}

          {!showLoading && connectionState === 'stale' && (
            <Box
              aria-live="polite"
              padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
              style={{
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              }}
            >
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Live feed delayed; showing latest available prices.
              </Text>
            </Box>
          )}

          <Box
            role="list"
            style={{
              display: 'grid',
              gridTemplateColumns: '1fr',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <style>
              {`
                @media (min-width: 1024px) {
                  .stock-grid-template {
                    grid-template-columns: repeat(3, minmax(0, 1fr)) !important;
                  }
                }
              `}
            </style>
            <Box
              className="stock-grid-template"
              style={{
                display: 'grid',
                gridTemplateColumns: '1fr',
                gap: 'var(--ggui-spacing-4, 16px)',
              }}
            >
              {liveStocks.map((item, index) => {
                const directionValue = item.changePercent ?? item.change ?? 0;
                const isPositive = directionValue >= 0;

                const priceValue = item.price ?? 0;
                const changeValue = item.change ?? 0;
                const percentValue = item.changePercent ?? 0;

                const priceText = `$${priceValue.toFixed(2)}`;
                const changeText = `${changeValue >= 0 ? '+' : ''}${changeValue.toFixed(2)}`;
                const percentText = `${percentValue >= 0 ? '+' : ''}${percentValue.toFixed(2)}%`;
                const arrow = isPositive ? '▲' : '▼';

                const trendColor = isPositive
                  ? 'var(--ggui-color-success-600, #16a34a)'
                  : 'var(--ggui-color-error-600, #dc2626)';

                const symbol = item.symbol || '--';
                const company = item.name || 'Unknown Company';

                return (
                  <Card
                    key={`${symbol}-${index}`}
                    padding="var(--ggui-spacing-4, 16px)"
                    radius="lg"
                    shadow="sm"
                    border
                  >
                    <Box
                      role="listitem"
                      aria-label={`${symbol}, current price ${priceText}, ${
                        isPositive ? 'up' : 'down'
                      } ${percentText}`}
                      style={{
                        border: `1px solid ${trendColor}`,
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        padding: 'var(--ggui-spacing-4, 16px)',
                        background: 'var(--ggui-color-surface, #fafafa)',
                        transition:
                          'border-color 200ms ease-in-out, box-shadow 200ms ease-in-out, transform 200ms ease-in-out',
                      }}
                    >
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        <Text
                          as="div"
                          size="2xl"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {symbol}
                        </Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {company}
                        </Text>
                        <Text
                          as="div"
                          size="xl"
                          weight="semibold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {priceText}
                        </Text>

                        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                          <Text variant="bodySmall" color={trendColor}>
                            {changeText}
                          </Text>
                          <Text variant="bodySmall" color={trendColor}>
                            {percentText}
                          </Text>
                          <Text as="span" variant="caption" color={trendColor} aria-hidden="true">
                            {arrow}
                          </Text>
                        </Stack>
                      </Stack>
                    </Box>
                  </Card>
                );
              })}
            </Box>
          </Box>
        </Stack>
      </Container>
    </Box>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (profile: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? ''
  );
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const nameError = name.trim() ? '' : 'Name is required.';
  const emailError = !email.trim()
    ? 'Email is required.'
    : !EMAIL_REGEX.test(email)
    ? 'Please enter a valid email address.'
    : '';

  const isStep1Valid = !nameError && !emailError && !!avatar;
  const isStep2Valid = !!role && !!theme;
  const canProceed = step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;

  const progressValue = useMemo(() => Math.round((step / 3) * 100), [step]);

  const roleOptions = props.roleOptions.map((r) => ({ value: r, label: r }));

  const submit = () => {
    if (!isStep1Valid || !isStep2Valid) return;
    props.complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        border
        radius="lg"
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          color: 'var(--ggui-color-onSurface, #18181b)',
          maxWidth: '640px',
          margin: '0 auto',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          <Stack
            gap={16}
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            }}
          >
            {step === 1 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={nameError || undefined}
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={emailError || undefined}
                />

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Choose an avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {props.avatarOptions.map((option) => {
                      const selected = option === avatar;
                      return (
                        <Button
                          key={option}
                          variant={selected ? 'primary' : 'outline'}
                          size="md"
                          onClick={() => setAvatar(option)}
                          aria-label={`Select avatar ${option}`}
                        >
                          {option}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={roleOptions}
                  placeholder="Select your role"
                  required
                  error={!role ? 'Role is required.' : undefined}
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />

                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>

                <Card
                  padding={16}
                  shadow="none"
                  border
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={8}>
                    <Text variant="body"><strong>Name:</strong> {name || '—'}</Text>
                    <Text variant="body"><strong>Email:</strong> {email || '—'}</Text>
                    <Text variant="body"><strong>Avatar:</strong> {avatar || '—'}</Text>
                    <Text variant="body"><strong>Role:</strong> {role || '—'}</Text>
                    <Text variant="body">
                      <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="body"><strong>Theme:</strong> {theme || '—'}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>

          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              size="md"
              disabled={step === 1}
              onClick={() => setStep((s) => Math.max(1, s - 1))}
            >
              {step === 3 ? 'Go Back' : 'Back'}
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                size="md"
                disabled={!canProceed}
                onClick={() => setStep((s) => Math.min(3, s + 1))}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" size="md" onClick={submit}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </>
  );
}
